import sys
import random

sys.setrecursionlimit(1 << 25)
input = sys.stdin.readline


# ---------- treap (ordered map) ----------
class Node:
    __slots__ = ('key', 'val', 'prio', 'left', 'right')

    def __init__(self, key, val):
        self.key = key          # left end of the interval
        self.val = val          # right end of the interval
        self.prio = random.getrandbits(30)
        self.left = None
        self.right = None


def split(root, key):
    """split into (<key) and (>=key)"""
    if root is None:
        return (None, None)
    if key <= root.key:
        left, right = split(root.left, key)
        root.left = right
        return (left, root)
    else:
        left, right = split(root.right, key)
        root.right = left
        return (root, right)


def merge(left, right):
    if not left or not right:
        return left or right
    if left.prio > right.prio:
        left.right = merge(left.right, right)
        return left
    else:
        right.left = merge(left, right.left)
        return right


def treap_insert(root, node):
    if root is None:
        return node
    if node.prio > root.prio:
        l, r = split(root, node.key)
        node.left = l
        node.right = r
        return node
    if node.key < root.key:
        root.left = treap_insert(root.left, node)
    elif node.key > root.key:
        root.right = treap_insert(root.right, node)
    else:                       # key already exists – update value
        root.val = node.val
    return root


def treap_erase(root, key):
    if root is None:
        return None
    if key == root.key:
        return merge(root.left, root.right)
    if key < root.key:
        root.left = treap_erase(root.left, key)
    else:
        root.right = treap_erase(root.right, key)
    return root


def treap_lower_bound(root, key):
    """node with smallest key >= given key, or None"""
    res = None
    while root:
        if root.key >= key:
            res = root
            root = root.left
        else:
            root = root.right
    return res


def treap_predecessor(root, key):
    """node with largest key < given key, or None"""
    res = None
    while root:
        if root.key < key:
            res = root
            root = root.right
        else:
            root = root.left
    return res


# ---------- main ----------
def solve() -> None:
    N, Q = map(int, input().split())
    ops = []
    for i in range(1, Q + 1):
        L, R, C = map(int, input().split())
        ops.append((L, R, C, i))

    # ---- connectivity test ----
    ops_by_L = sorted(ops, key=lambda x: (x[0], x[1]))
    cur = 0
    connected = True
    for L, R, _, _ in ops_by_L:
        if L > cur:
            connected = False
            break
        cur = max(cur, R)
    if not connected or cur != N:
        print(-1)
        return

    # ---- build initial interval set ----
    root = None
    for v in range(1, N + 1):
        root = treap_insert(root, Node(v, v))

    # ---- Kruskal on the special vertices ----
    ops_by_C = sorted(ops, key=lambda x: (x[2], x[0]))
    ans = 0

    for L, R, C, _ in ops_by_C:
        merged_l = L
        merged_r = R

        # first interval that can intersect
        it = treap_lower_bound(root, L)
        pred = treap_predecessor(root, L)
        if pred is not None and pred.val >= L:
            it = pred

        while it is not None and it.key <= R:
            l_i = it.key
            r_i = it.val
            ans += C
            merged_l = min(merged_l, l_i)
            merged_r = max(merged_r, r_i)

            nxt = treap_lower_bound(root, l_i + 1)
            root = treap_erase(root, l_i)
            it = nxt

        root = treap_insert(root, Node(merged_l, merged_r))

    print(ans)


if __name__ == "__main__":
    solve()

