import sys

def solve() -> None:
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    M = int(next(it))
    A = [int(next(it)) for _ in range(N)]

    total_A = sum(A)
    if total_A <= M:
        print("infinite")
        return

    max_a = max(A)
    lo = 0
    hi = max_a  # we know f(max_a) > M because total_A > M

    # binary search for the greatest x with sum(min(x, A_i)) <= M
    while lo < hi:
        mid = (lo + hi + 1) // 2
        s = 0
        for a in A:
            # add min(mid, a) efficiently
            if a < mid:
                s += a
            else:
                s += mid
            # early stop if already exceeds M (optional, but speeds up a bit)
            if s > M:
                break
        if s <= M:
            lo = mid
        else:
            hi = mid - 1

    print(lo)

