import math

class Solution:
    def nonSpecialCount(self, l: int, r: int) -> int:
        # total numbers in the inclusive interval [l, r]
        total = r - l + 1

        # a special number has exactly 3 positive divisors,
        # which means it is p^2 for some prime p.
        # So we only need primes up to sqrt(r).
        limit = math.isqrt(r)

        # Sieve of Eratosthenes to find all primes ≤ limit
        is_prime = [True] * (limit + 1)
        is_prime[0] = is_prime[1] = False
        for i in range(2, int(limit ** 0.5) + 1):
            if is_prime[i]:
                for j in range(i * i, limit + 1, i):
                    is_prime[j] = False

        # count prime squares that fall inside [l, r]
        special_cnt = 0
        for p in range(2, limit + 1):
            if is_prime[p]:
                sq = p * p
                if l <= sq <= r:
                    special_cnt += 1

        # numbers that are not special = total - special numbers
        return total - special_cnt

from typing import List

class DSU:
    def __init__(self, n: int):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x: int) -> int:
        # path compression
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x

    def union(self, a: int, b: int) -> None:
        ra, rb = self.find(a), self.find(b)
        if ra == rb:
            return
        if self.rank[ra] < self.rank[rb]:
            self.parent[ra] = rb
        elif self.rank[ra] > self.rank[rb]:
            self.parent[rb] = ra
        else:
            self.parent[rb] = ra
            self.rank[ra] += 1


class Solution:
    def canReachCorner(self, xCorner: int, yCorner: int,
                       circles: List[List[int]]) -> bool:
        # 1) corners must not belong to any circle
        for x, y, r in circles:
            if (x - 0) * (x - 0) + (y - 0) * (y - 0) <= r * r:
                return False
            if (x - xCorner) * (x - xCorner) + (y - yCorner) * (y - yCorner) <= r * r:
                return False

        m = len(circles)
        dsu = DSU(m + 4)          # 0:left 1:right 2:bottom 3:top

        # helper: squared distance from a point (cx,cy) to a side segment
        def dist2_to_left(cx: int, cy: int) -> int:
            y_mid = cy
            if y_mid < 0:
                y_mid = 0
            elif y_mid > yCorner:
                y_mid = yCorner
            return cx * cx + (cy - y_mid) * (cy - y_mid)

        def dist2_to_right(cx: int, cy: int) -> int:
            y_mid = cy
            if y_mid < 0:
                y_mid = 0
            elif y_mid > yCorner:
                y_mid = yCorner
            dx = cx - xCorner
            return dx * dx + (cy - y_mid) * (cy - y_mid)

        def dist2_to_bottom(cx: int, cy: int) -> int:
            x_mid = cx
            if x_mid < 0:
                x_mid = 0
            elif x_mid > xCorner:
                x_mid = xCorner
            return (cx - x_mid) * (cx - x_mid) + cy * cy

        def dist2_to_top(cx: int, cy: int) -> int:
            x_mid = cx
            if x_mid < 0:
                x_mid = 0
            elif x_mid > xCorner:
                x_mid = xCorner
            dy = cy - yCorner
            return (cx - x_mid) * (cx - x_mid) + dy * dy

        # 2) circle – side touches
        for i, (cx, cy, r) in enumerate(circles):
            node = i + 4
            r2 = r * r
            if dist2_to_left(cx, cy) <= r2:
                dsu.union(node, 0)          # left
            if dist2_to_right(cx, cy) <= r2:
                dsu.union(node, 1)          # right
            if dist2_to_bottom(cx, cy) <= r2:
                dsu.union(node, 2)          # bottom
            if dist2_to_top(cx, cy) <= r2:
                dsu.union(node, 3)          # top

        # 3) circle – circle touches
        for i in range(m):
            x1, y1, r1 = circles[i]
            for j in range(i + 1, m):
                x2, y2, r2 = circles[j]
                dx = x1 - x2
                dy = y1 - y2
                if dx * dx + dy * dy <= (r1 + r2) * (r1 + r2):
                    dsu.union(i + 4, j + 4)

        # 4) final test – opposite sides in the same component ?
        if dsu.find(0) == dsu.find(1) or dsu.find(2) == dsu.find(3):
            return False
        return True

from typing import List

class Solution:
    def shortestDistanceAfterQueries(self, n: int, queries: List[List[int]]) -> List[int]:
        # adjacency list for the directed graph
        adj = [[] for _ in range(n)]
        # initial chain 0->1->2->...->n-1
        for i in range(n - 1):
            adj[i].append(i + 1)

        ans: List[int] = []
        INF = 10 ** 9

        for u, v in queries:
            # add the new road
            adj[u].append(v)

            # compute shortest distance from 0 to n-1
            dist = [INF] * n
            dist[0] = 0

            # because all edges go forward (u < v) the graph is a DAG.
            # Processing vertices in increasing order yields a topological order.
            for i in range(n):
                if dist[i] == INF:
                    continue
                for nb in adj[i]:
                    if dist[nb] > dist[i] + 1:
                        dist[nb] = dist[i] + 1

            ans.append(dist[-1])

        return ans

from typing import List

class Solution:
    def finalPositionOfSnake(self, n: int, commands: List[str]) -> int:
        # Start at the top‑left cell (row 0, column 0)
        row, col = 0, 0

        # Apply each movement command
        for cmd in commands:
            if cmd == "UP":
                row -= 1
            elif cmd == "DOWN":
                row += 1
            elif cmd == "LEFT":
                col -= 1
            elif cmd == "RIGHT":
                col += 1
            # The problem guarantees we stay inside the grid, so no bounds check needed

        # Convert (row, col) back to the linear index used by the grid
        return row * n + col

