class Solution:
    def numberOfAlternatingGroups(self, colors: List[int]) -> int:
        n = len(colors)
        count = 0

        for i in range(n):
            left = colors[i - 1]                     # wraps automatically to the last element
            mid = colors[i]
            right = colors[(i + 1) % n]              # wraps to the first element

            if left == right and left != mid:
                count += 1

        return count

class Solution:
    def minimumLength(self, s: str) -> int:
        # frequency of each lower‑case letter
        freq = [0] * 26
        for ch in s:
            freq[ord(ch) - ord('a')] += 1

        ans = 0
        for k in freq:
            if k <= 2:
                ans += k               # cannot delete anything
            else:
                # k >= 3
                if k % 2 == 1:         # odd -> we can end with 1
                    ans += 1
                else:                  # even -> we can end with 2
                    ans += 2
        return ans

