from collections import defaultdict

class Solution:
    def winningPlayerCount(self, n: int, pick: List[List[int]]) -> int:
        # cnt[p] : dict {color : frequency} for player p
        cnt = [defaultdict(int) for _ in range(n)]

        for player, color in pick:
            cnt[player][color] += 1

        winners = 0
        for i in range(n):
            needed = i + 1               # must have at least i+1 balls of one color
            for c in cnt[i].values():
                if c >= needed:
                    winners += 1
                    break                # player i already wins, stop checking other colors

        return winners

from typing import List

class Solution:
    def minFlips(self, grid: List[List[int]]) -> int:
        m = len(grid)
        n = len(grid[0])

        # Flips required to make every row a palindrome.
        row_flips = 0
        half_cols = n // 2
        for i in range(m):
            row = grid[i]
            for j in range(half_cols):
                if row[j] != row[n - 1 - j]:
                    row_flips += 1

        # Flips required to make every column a palindrome.
        col_flips = 0
        half_rows = m // 2
        for j in range(n):
            for i in range(half_rows):
                if grid[i][j] != grid[m - 1 - i][j]:
                    col_flips += 1

        # We may choose either rows or columns, whichever needs fewer flips.
        return min(row_flips, col_flips)

import sys

def solve() -> None:
    data = sys.stdin.read().splitlines()
    if not data:
        return
    N = int(data[0].strip())
    S = [line.strip() for line in data[1:1 + N]]
    M = max(len(s) for s in S)          # maximum length

    # rows[r] will collect characters for T_{r+1}
    rows = [[] for _ in range(M)]

    # columns correspond to the strings in reverse order:
    # column 1 -> S_N, column 2 -> S_{N-1}, ..., column N -> S_1
    for col in range(N):
        cur = S[N - 1 - col]            # reversed list
        L = len(cur)
        for r in range(M):
            if r < L:
                rows[r].append(cur[r])
            else:
                rows[r].append('*')

    # Remove trailing '*' so that no T_i ends with '*'
    for r in range(M):
        while rows[r] and rows[r][-1] == '*':
            rows[r].pop()

    # Output
    out = '\n'.join(''.join(row) for row in rows)
    sys.stdout.write(out)

