import sys
sys.setrecursionlimit(1 << 25)

INF = 10 ** 18           # maximal answer


# ---------- convex hull utilities ----------
def is_bad(l1, l2, l3):
    """True iff line l2 is unnecessary between l1 and l3
       (slopes are strictly increasing)."""
    # (q2 - q1)*(p3 - p2) >= (q3 - q2)*(p2 - p1)
    return (l2[1] - l1[1]) * (l3[0] - l2[0]) >= (l3[1] - l2[1]) * (l2[0] - l1[0])


def make_hull(lines):
    """build upper envelope, lines = list of (p,q), p >= 0, q >= 0"""
    # sort by slope
    lines = sorted(lines, key=lambda x: x[0])
    hull = []
    for p, q in lines:
        # keep only the best intercept for a repeated slope
        if hull and hull[-1][0] == p:
            if q <= hull[-1][1]:
                continue
            else:
                hull.pop()
        while len(hull) >= 2 and is_bad(hull[-2], hull[-1], (p, q)):
            hull.pop()
        hull.append((p, q))
    return hull


def compose(left, right):
    """upper envelope of the concatenation left then right"""
    cand = []
    for pL, qL in left:
        for pR, qR in right:
            # new slope, cap to INF
            if pL == 0 or pR == 0:
                p = 0
            else:
                if pL > INF // pR:
                    p = INF
                else:
                    p = pL * pR
                    if p > INF:
                        p = INF
            # new intercept, cap to INF
            if qL == 0:
                qq = qR
            else:
                if pR > INF // qL:
                    qq = INF
                else:
                    qq = qL * pR + qR
                    if qq > INF:
                        qq = INF
            cand.append((p, qq))

    # build envelope from candidates
    cand.sort(key=lambda x: x[0])
    hull = []
    for p, q in cand:
        if hull and hull[-1][0] == p:
            if q > hull[-1][1]:
                hull[-1] = (p, q)
            continue
        while len(hull) >= 2 and is_bad(hull[-2], hull[-1], (p, q)):
            hull.pop()
        hull.append((p, q))
    return hull


def eval_hull(hull, x):
    """maximum of p*x+q over all lines of hull (hull size ≤ 61)"""
    best = -1
    best_val = -1
    # linear scan – fast enough
    for p, q in hull:
        v = p * x + q
        if v > best_val:
            best_val = v
    return best_val


# ---------- segment tree ----------
class SegTree:
    def __init__(self, A, B):
        self.n = len(A)
        self.size = 1 << (self.n - 1).bit_length()
        self.tree = [None] * (2 * self.size)

        # leaves
        for i in range(self.size):
            if i < self.n:
                leaf = make_hull([(1, A[i]), (B[i], 0)])
            else:
                leaf = [(1, 0)]                     # dummy, never used
            self.tree[self.size + i] = leaf

        # internal nodes
        for i in range(self.size - 1, 0, -1):
            self.tree[i] = compose(self.tree[i << 1], self.tree[i << 1 | 1])

    # point update
    def set leaf(self, pos, Avalue, Bvalue):
        i = pos + self.size
        self.tree[i] = make_hull([(1, Avalue), (Bvalue, 0)])
        i >>= 1
        while i:
            self.tree[i] = compose(self.tree[i << 1], self.tree[i << 1 | 1])
            i >>= 1

    # range query, returns the maximal value
    def query(self, l, r):
        # recursive, left to right order
        return self._query(1, 0, self.size - 1, l, r, 0)

    def _query(self, node, nl, nr, ql, qr, cur):
        if ql <= nl and nr <= qr:
            return eval_hull(self.tree[node], cur)
        mid = (nl + nr) // 2
        if ql <= mid:
            cur = self._query(node << 1, nl, mid, ql, qr, cur)
        if qr > mid:
            cur = self._query(node << 1 | 1, mid + 1, nr, ql, qr, cur)
        return cur


# ---------- main ----------
def solve() -> None:
    data = list(map(int, sys.stdin.buffer.read().split()))
    it = iter(data)
    N = next(it)
    A = [next(it) for _ in range(N)]
    B = [next(it) for _ in range(N)]
    Q = next(it)

    seg = SegTree(A, B)

    out_lines = []
    for _ in range(Q):
        typ = next(it)
        if typ == 1:
            i = next(it) - 1
            x = next(it)
            seg.set_leaf(i, x, B[i])
        elif typ == 2:
            i = next(it) - 1
            x = next(it)
            seg.set_leaf(i, A[i], x)
        else:               # typ == 3
            l = next(it) - 1
            r = next(it) - 1
            ans = seg.query(l, r)
            out_lines.append(str(ans))

    sys.stdout.write("\n".join(out_lines))


