import sys

INF = 10 ** 9

def distance_transform(arr):
    """arr[0..100]; returns f[t] = min_r arr[r] + |r-t| for t = 0..100"""
    f = arr[:]                     # copy
    # forward
    for i in range(2, 101):
        if f[i - 1] + 1 < f[i]:
            f[i] = f[i - 1] + 1
    # backward
    for i in range(99, 0, -1):
        if f[i + 1] + 1 < f[i]:
            f[i] = f[i + 1] + 1
    return f


def solve() -> None:
    input = sys.stdin.readline
    N = int(input())
    A = []
    S = []
    for _ in range(N):
        a, s = input().split()
        A.append(int(a))
        S.append(s)

    # dp[l][r] , indices 0..100, 0 is never used (kept INF)
    dp = [[INF] * 101 for _ in range(101)]
    for l in range(1, 101):
        row = dp[l]
        for r in range(1, 101):
            row[r] = 0                     # initial placement is free

    for idx in range(N):
        a = A[idx]
        hand = S[idx]
        new_dp = [[INF] * 101 for _ in range(101)]

        if hand == 'L':
            # left hand must end at a
            for l in range(1, 101):
                row = dp[l]
                # distance transform of this row
                f = distance_transform(row)        # f[t] = min_r (row[r] + |r-t|)
                add = abs(l - a)
                target = new_dp[a]                 # row that will hold left = a
                for r2 in range(1, 101):
                    val = add + f[r2]
                    if val < target[r2]:
                        target[r2] = val
        else:   # hand == 'R'
            for r in range(1, 101):
                # column dp[*][r]
                col = [dp[l][r] for l in range(101)]
                f = distance_transform(col)        # f[t] = min_l (dp[l][r] + |l-t|)
                add = abs(r - a)
                for l2 in range(1, 101):
                    val = add + f[l2]
