class Solution:
    def countKConstraintSubstrings(self, s: str, k: int) -> int:
        n = len(s)
        ans = 0

        # enumerate all possible start positions
        for i in range(n):
            zeros = 0
            ones = 0
            # extend the substring from i to j
            for j in range(i, n):
                if s[j] == '0':
                    zeros += 1
                else:
                    ones += 1

                # a substring is valid if either zeros ≤ k or ones ≤ k
                if zeros <= k or ones <= k:
                    ans += 1
                else:
                    # once both counts exceed k, extending further will keep both > k
                    break

        return ans

