class Solution:
    def countPairs(self, nums: List[int]) -> int:
        n = len(nums)

        # For each number, compute the set of integers we can obtain by
        # swapping at most one pair of its digits (including the original
        # number, i.e. the “no swap” case).
        reachable = []
        for x in nums:
            s = str(x)                 # original digit string
            L = len(s)
            cur = {x}                  # zero swaps
            for i in range(L):
                for j in range(i + 1, L):
                    if s[i] == s[j]:
                        # swapping equal digits does not change the number
                        continue
                    # perform the swap
                    lst = list(s)
                    lst[i], lst[j] = lst[j], lst[i]
                    val = int(''.join(lst))   # leading zeros are ignored
                    cur.add(val)
            reachable.append(cur)

        # Count pairs (i, j) with i < j that are "almost equal"
        ans = 0
        for i in range(n):
            for j in range(i + 1, n):
                if nums[j] in reachable[i] or nums[i] in reachable[j]:
                    ans += 1

        return ans

class Solution:
    def checkTwoChessboards(self, coordinate1: str, coordinate2: str) -> bool:
        # Helper function to determine the color of a square
        def is_black(coord: str) -> bool:
            # Convert the column letter to a number (a -> 1, ..., h -> 8)
            col = ord(coord[0]) - ord('a') + 1
            # Row is given as a digit '1' to '8'
            row = int(coord[1])
            # On a standard chessboard, a square is black when (col + row) is even
            return (col + row) % 2 == 0

        # Both squares have the same color if their black/white status matches
        return is_black(coordinate1) == is_black(coordinate2)

