class Solution:
    def maxScore(self, grid: List[List[int]]) -> int:
        # ---------- 1. collect distinct values ----------
        R = len(grid)
        vals = sorted({v for row in grid for v in row})
        M = len(vals)

        # ---------- 2. build cost matrix ----------
        INF = 10 ** 9          # larger than any possible total cost
        N = R + M               # square matrix size

        # cost[i][j] = -weight  (we minimise)
        cost = [[0] * N for _ in range(N)]

        # map value -> column index
        val_index = {v: idx for idx, v in enumerate(vals)}

        # real rows -> real value columns
        for i in range(R):
            row_vals = set(grid[i])
            for j in range(M):
                if vals[j] in row_vals:
                    cost[i][j] = -vals[j]          # allowed edge
                else:
                    cost[i][j] = INF                # forbidden edge

        # dummy columns (do not take a value) – weight 0, cost 0
        for i in range(R):
            for j in range(M, N):
                cost[i][j] = 0

        # dummy rows – cost 0 everywhere (only needed to make matrix square)
        for i in range(R, N):
            for j in range(N):
                cost[i][j] = 0

        # ---------- 3. Hungarian algorithm (minimisation) ----------
        n = N
        u = [0] * (n + 1)
        v = [0] * (n + 1)
        p = [0] * (n + 1)
        way = [0] * (n + 1)

        for i in range(1, n + 1):
            p[0] = i
            j0 = 0
            minv = [float('inf')] * (n + 1)
            used = [False] * (n + 1)
            while True:
                used[j0] = True
                i0 = p[j0]
                delta = float('inf')
                j1 = 0
                for j in range(1, n + 1):
                    if not used[j]:
                        cur = cost[i0 - 1][j - 1] - u[i0] - v[j]
                        if cur < minv[j]:
                            minv[j] = cur
                            way[j] = j0
                        if minv[j] < delta:
                            delta = minv[j]
                            j1 = j
                for j in range(0, n + 1):
                    if used[j]:
                        u[p[j]] += delta
                        v[j] -= delta
                    else:
                        minv[j] -= delta
                j0 = j1
                if p[j0] == 0:
                    break

            # augmenting
            while True:
                j1 = way[j0]
                p[j0] = p[j1]
                j0 = j1
                if j0 == 0:
                    break

        # ---------- 4. extract answer ----------
        # p[j] = row assigned to column j (1‑based)
        assignment = [-1] * n
        for j in range(1, n + 1):
            if p[j] != 0:
                assignment[p[j] - 1] = j - 1

        total = 0
        for i in range(R):          # only real rows matter
            col = assignment[i]
            if col < M:              # real value column
                total += vals[col]   # weight = -cost, but cost = -value
        return total

