# ---------- line and Li Chao tree ----------
class Line:
    __slots__ = ('m', 'b')
    def __init__(self, m: int, b: int):
        self.m = m          # slope
        self.b = b          # intercept
    def value(self, x: int) -> int:
        return self.m * x + self.b


class Node:
    __slots__ = ('line', 'left', 'right')
    def __init__(self, line: Line):
        self.line = line
        self.left = None
        self.right = None


class LiChaoTree:
    """Maximum Li Chao tree for integer x in [x_left, x_right] (inclusive)."""
    def __init__(self, x_left: int, x_right: int):
        self.x_left = x_left
        self.x_right = x_right
        self.root = None

    def add_line(self, new_line: Line):
        if self.root is None:
            self.root = Node(new_line)
            return
        self._add(self.root, self.x_left, self.x_right, new_line)

    def _add(self, node: Node, l: int, r: int, new_line: Line):
        mid = (l + r) // 2
        # keep the line that is better at mid in the node
        if new_line.value(mid) > node.line.value(mid):
            node.line, new_line = new_line, node.line
        if l == r:
            return

        left_is_better = new_line.value(l) > node.line.value(l)
        mid_is_better = new_line.value(mid) > node.line.value(mid)

        # decide which side the worse line can still be better
        if left_is_better != mid_is_better:
            # go to left child
            if node.left is None:
                node.left = Node(new_line)
            else:
                self._add(node.left, l, mid, new_line)
        else:
            # go to right child
            if node.right is None:
                node.right = Node(new_line)
            else:
                self._add(node.right, mid + 1, r, new_line)

    def query(self, x: int) -> int:
        return self._query(self.root, self.x_left, self.x_right, x)

    def _query(self, node: Node, l: int, r: int, x: int) -> int:
        if node is None:
            # should never happen after the first line is inserted
            return -10**30
        res = node.line.value(x)
        if l == r:
            return res
        mid = (l + r) // 2
        if x <= mid:
            return max(res, self._query(node.left, l, mid, x))
        else:
            return max(res, self._query(node.right, mid + 1, r, x))


