class Solution:
    def findMaximumScore(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 1:
            return 0                     # already at the last index

        dp = [0] * n
        dp[0] = 0

        # tree covers x = 0 … n (j never reaches n, but it is safe)
        tree = LiChaoTree(0, n)

        # line for i = 0 : y = nums[0] * x + (dp[0] - 0*nums[0]) = nums[0] * x
        tree.add_line(Line(nums[0], dp[0]))

        for j in range(1, n):
            dp[j] = tree.query(j)                     # best score to reach j
            # line for index j
            intercept = dp[j] - j * nums[j]
            tree.add_line(Line(nums[j], intercept))

        return dp[-1]

