class Solution:
    def minValidStrings(self, words: List[str], target: str) -> int:
        # ---------- build a trie containing all prefixes of the given words ----------
        class TrieNode:
            __slots__ = ('children',)
            def __init__(self):
                self.children = {}          # char -> TrieNode

        root = TrieNode()
        for w in words:
            node = root
            for ch in w:
                if ch not in node.children:
                    node.children[ch] = TrieNode()
                node = node.children[ch]

        n = len(target)
        INF = n + 5                         # any value > n is enough
        dp = [INF] * (n + 1)
        dp[n] = 0                            # empty suffix needs 0 strings

        # ---------- DP from right to left ----------
        for i in range(n - 1, -1, -1):
            node = root
            # try every prefix that starts at position i
            for j in range(i, n):
                c = target[j]
                if c not in node.children:
                    break                     # no longer a prefix of any word
                node = node.children[c]       # we have a valid prefix target[i:j+1]
                # we can use this prefix and then cover the rest with dp[j+1]
                if dp[j + 1] + 1 < dp[i]:
                    dp[i] = dp[j + 1] + 1

        return dp[0] if dp[0] != INF else -1

