class Solution:
    def resultsArray(self, nums: List[int], k: int) -> List[int]:
        n = len(nums)
        # If k == 1, each single element subarray is trivially consecutive
        if k == 1:
            return nums[:]  # return a copy to match expected list type

        res: List[int] = []
        # Slide a window of size k over the array
        for i in range(n - k + 1):
            valid = True
            # Check that every consecutive pair inside the window differs by exactly 1
            for j in range(i, i + k - 1):
                if nums[j + 1] != nums[j] + 1:
                    valid = False
                    break
            # If the window is valid, its power is its maximum element (the last one)
            if valid:
                res.append(nums[i + k - 1])
            else:
                res.append(-1)

        return res

class Solution:
    def generateKey(self, num1: int, num2: int, num3: int) -> int:
        # Pad each number to exactly four digits with leading zeros.
        s1 = f"{num1:04d}"
        s2 = f"{num2:04d}"
        s3 = f"{num3:04d}"

        # For each position, take the smallest digit among the three numbers.
        key_str = ''.join(min(d1, d2, d3) for d1, d2, d3 in zip(s1, s2, s3))

        # Convert to int to remove any leading zeros (e.g., "0000" → 0).
        return int(key_str)

class Solution:
    def validSubstringCount(self, word1: str, word2: str) -> int:
        n, m = len(word1), len(word2)
        if m > n:
            return 0

        # count needed frequencies
        need = [0] * 26
        for ch in word2:
            need[ord(ch) - 97] += 1

        distinct = sum(1 for x in need if x > 0)   # how many different letters are required

        # quick impossibility test
        total = [0] * 26
        for ch in word1:
            total[ord(ch) - 97] += 1
        for i in range(26):
            if need[i] > total[i]:
                return 0

        freq = [0] * 26
        missing = distinct          # how many required letters are still unsatisfied
        left = right = 0
        ans = 0

        while left < n:
            # enlarge right until we meet the requirement or run out of characters
            while right < n and missing > 0:
                idx = ord(word1[right]) - 97
                freq[idx] += 1
                if freq[idx] == need[idx]:
                    missing -= 1
                right += 1

            if missing == 0:
                # every substring that starts at `left` and ends at or after `right-1` is valid
                ans += n - right + 1
            else:
                # cannot satisfy the requirement any more
                break

            # move left forward, shrink the window
            idxL = ord(word1[left]) - 97
            if freq[idxL] == need[idxL]:
                # we are about to drop below the required amount for this letter
                missing += 1
            freq[idxL] -= 1
            left += 1

        return ans

class Solution:
    def countOfSubstrings(self, word: str, k: int) -> int:
        """
        Returns the number of substrings of `word` that contain each vowel
        a, e, i, o, u at least once and contain exactly `k` consonants.
        """
        # map each vowel to a bit position
        vowel_bit = {'a': 0, 'e': 1, 'i': 2, 'o': 3, 'u': 4}
        FULL_MASK = (1 << 5) - 1          # 0b11111 == 31
        n = len(word)
        answer = 0

        for left in range(n):
            # A valid substring needs at least 5 vowels + k consonants
            if n - left < 5 + k:
                break                     # not enough characters left

            mask = 0
            consonants = 0

            for right in range(left, n):
                ch = word[right]
                if ch in vowel_bit:
                    mask |= 1 << vowel_bit[ch]
                else:
                    consonants += 1

                # Once we have too many consonants we can never return to k
                if consonants > k:
                    break

                # Check the two required conditions
                if mask == FULL_MASK and consonants == k:
                    answer += 1

        return answer

