            visited[x] = True
            for w in adj[x]:
                if not visited[w]:
                    dfs1(w)
            order.append(x)

        for v in vertices:
            if not visited[v]:
                dfs1(v)

        # second pass – reverse graph, assign component ids
        comp_id = [-1] * 26
        cur_id = 0

        def dfs2(x):
            comp_id[x] = cur_id
            for w in radj[x]:
                if comp_id[w] == -1:
                    dfs2(w)

        for v in reversed(order):
            if comp_id[v] == -1:
                dfs2(v)
                cur_id += 1

        scc_cnt = cur_id
        # ---------- build condensation ----------
        in_scc = [set() for _ in range(scc_cnt)]
        out_scc = [set() for _ in range(scc_cnt)]

        for u, v in edges:
            su = comp_id[u]
            sv = comp_id[v]
            if su != sv:
                out_scc[su].add(sv)
                in_scc[sv].add(su)

        src = sum(1 for i in range(scc_cnt) if len(in_scc[i]) == 0)
        snk = sum(1 for i in range(scc_cnt) if len(out_scc[i]) == 0)

        answer += max(1, src, snk)

    print(answer)


