import sys

def solve() -> None:
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    N = int(next(it))
    M = int(next(it))

    rows = set()
    cols = set()
    sums = set()
    diffs = set()

    for _ in range(M):
        a = int(next(it))
        b = int(next(it))
        rows.add(a)
        cols.add(b)
        sums.add(a + b)
        diffs.add(a - b)

    # ----- length of a diagonal ---------------------------------
    def main_len(s: int) -> int:
        # s is between 2 and 2*N
        if s <= N + 1:
            return s - 1
        else:
            return 2 * N + 1 - s

    def anti_len(d: int) -> int:
        # d is between -(N-1) and N-1
        return N - abs(d)

    # ----- single families ---------------------------------------
    single = len(rows) * N + len(cols) * N
    single += sum(main_len(s) for s in sums)
    single += sum(anti_len(d) for d in diffs)

    # ----- pairwise intersections --------------------------------
    pair = 0

    # row – column
    pair += len(rows) * len(cols)

    # row – main diagonal
    for i in rows:
        for s in sums:
            j = s - i
            if 1 <= j <= N:
                pair += 1

    # row – anti diagonal
    for i in rows:
        for d in diffs:
            j = i - d
            if 1 <= j <= N:
                pair += 1

    # column – main diagonal
    for j in cols:
        for s in sums:
            i = s - j
            if 1 <= i <= N:
                pair += 1

    # column – anti diagonal
    for j in cols:
        for d in diffs:
            i = d + j
            if 1 <= i <= N:
                pair += 1

    # main – anti diagonal
    for s in sums:
        for d in diffs:
            if (s + d) & 1:      # parity check
                continue
            i = (s + d) // 2
            j = (s - d) // 2
            if 1 <= i <= N and 1 <= j <= N:
                pair += 1

    # ----- triple intersections ----------------------------------
    triple = 0

    # R ∩ C ∩ S
    for i in rows:
        for j in cols:
            if (i + j) in sums:
                triple += 1

    # R ∩ C ∩ D
    for i in rows:
        for j in cols:
            if (i - j) in diffs:
                triple += 1

    # R ∩ S ∩ D
    for i in rows:
        for s in sums:
            j = s - i
            if 1 <= j <= N:
                if (i - j) in diffs:
                    triple += 1

    # C ∩ S ∩ D
    for j in cols:
        for s in sums:
            i = s - j
            if 1 <= i <= N:
                if (i - j) in diffs:
                    triple += 1

    # ----- fourfold intersection ---------------------------------
    quad = 0
    for i in rows:
        for j in cols:
            if (i + j) in sums and (i - j) in diffs:
                quad += 1

    # ----- union size --------------------------------------------
    union = single - pair + triple - quad

    # ----- answer ------------------------------------------------
    total = N * N
    answer = total - union
    print(answer)


