def solve() -> None:
    data = sys.stdin.buffer.read().split()
    it = iter(data)
    N = int(next(it))
    K = int(next(it))
    # 1‑based permutation
    f = [0] * (N + 1)
    for i in range(1, N + 1):
        f[i] = int(next(it))

    visited = [False] * (N + 1)
    ans = [0] * (N + 1)

    # cache of (2^K mod L) to avoid repeated pow for equal lengths
    shift_cache = {}

    for i in range(1, N + 1):
        if not visited[i]:
            # collect the whole cycle
            cur = i
            cycle = []
            while not visited[cur]:
                visited[cur] = True
                cycle.append(cur)
                cur = f[cur]

            L = len(cycle)
            # compute 2^K modulo L
            if L not in shift_cache:
                shift_cache[L] = pow(2, K, L)
            shift = shift_cache[L]

            if shift == 0:
                # identity on this cycle
                for idx, v in enumerate(cycle):
                    ans[v] = cycle[idx]
            else:
                for idx, v in enumerate(cycle):
                    target = cycle[(idx + shift) % L]
                    ans[v] = target

    sys.stdout.write(' '.join(str(ans[i]) for i in range(1, N + 1)))

