    answer = 1  # at least the single character '/'
    for i, ch in enumerate(S):
        if ch != '/':
            continue
        left = L[i - 1] if i > 0 else 0
        right = R[i + 1] if i + 1 < n else 0
        k = left if left < right else right
        length = 2 * k + 1
        if length > answer:
            answer = length

