from collections import defaultdict

def solve() -> None:
    data = sys.stdin.buffer.read().split()
    it = iter(data)

    N = int(next(it))
    M = int(next(it))
    Sx = int(next(it))
    Sy = int(next(it))

    houses = [(int(next(it)), int(next(it))) for _ in range(N)]

    # intervals collected while reading the moves
    vertical_intervals = defaultdict(list)   # x -> [(y_low, y_high), ...]
    horizontal_intervals = defaultdict(list) # y -> [(x_low, x_high), ...]

    cx, cy = Sx, Sy

    for _ in range(M):
        d = next(it)            # b'U', b'D', b'L' or b'R'
        c = int(next(it))

        if d == b'U':
            ny = cy + c
            low, high = cy, ny
            if low > high:
                low, high = high, low
            vertical_intervals[cx].append((low, high))
            cy = ny
        elif d == b'D':
            ny = cy - c
            low, high = ny, cy
            if low > high:
                low, high = high, low
            vertical_intervals[cx].append((low, high))
            cy = ny
        elif d == b'R':
            nx = cx + c
            low, high = cx, nx
            if low > high:
                low, high = high, low
            horizontal_intervals[cy].append((low, high))
            cx = nx
        else:               # b'L'
            nx = cx - c
            low, high = nx, cx
            if low > high:
                low, high = high, low
            horizontal_intervals[cy].append((low, high))
            cx = nx

    # ------- build union of intervals for each line -------
    vertical_merged = {}
    for x, segs in vertical_intervals.items():
        segs.sort(key=lambda p: p[0])
        merged = []
        for lo, hi in segs:
            if not merged:
                merged.append([lo, hi])
            else:
                if lo <= merged[-1][1] + 1:           # overlap or touch
                    if hi > merged[-1][1]:
                        merged[-1][1] = hi
                else:
                    merged.append([lo, hi])
        lows = [iv[0] for iv in merged]
        highs = [iv[1] for iv in merged]
        vertical_merged[x] = (lows, highs)

    horizontal_merged = {}
    for y, segs in horizontal_intervals.items():
        segs.sort(key=lambda p: p[0])
        merged = []
        for lo, hi in segs:
            if not merged:
                merged.append([lo, hi])
            else:
                if lo <= merged[-1][1] + 1:
                    if hi > merged[-1][1]:
                        merged[-1][1] = hi
                else:
                    merged.append([lo, hi])
        lows = [iv[0] for iv in merged]
        highs = [iv[1] for iv in merged]
        horizontal_merged[y] = (lows, highs)

    # ------- count visited houses -------
    visited_cnt = 0
    for hx, hy in houses:
        # vertical check
        if hx in vertical_merged:
            lows, highs = vertical_merged[hx]
            idx = bisect.bisect_right(lows, hy) - 1
            if idx >= 0 and lows[idx] <= hy <= highs[idx]:
                visited_cnt += 1
                continue
        # horizontal check
        if hy in horizontal_merged:
            lows, highs = horizontal_merged[hy]
            idx = bisect.bisect_right(lows, hx) - 1
            if idx >= 0 and lows[idx] <= hx <= highs[idx]:
                visited_cnt += 1

    sys.stdout.write(f"{cx} {cy} {visited_cnt}")

