MOD = 998244353

def solve() -> None:
    data = sys.stdin.buffer.read().split()
    if not data:
        return
    it = iter(data)
    n = int(next(it))
    a = [int(next(it)) for _ in range(n)]

    max_a = max(a)

    # powers of two
    pow2 = [1] * (n + 1)
    for i in range(1, n + 1):
        pow2[i] = (pow2[i - 1] << 1) % MOD

    # Euler's totient
    phi = list(range(max_a + 1))
    for i in range(2, max_a + 1):
        if phi[i] == i:                     # i is prime
            step = i
            for j in range(i, max_a + 1, step):
                phi[j] -= phi[j] // i

    # divisors for every number up to max_a
    divisors = [[] for _ in range(max_a + 1)]
    for d in range(1, max_a + 1):
        for m in range(d, max_a + 1, d):
            divisors[m].append(d)

    cum = [0] * (max_a + 1)      # cum[d] = sum_{p already processed, d|A_p} 2^{p-1}
    dp = 0
    out = []

    for idx, val in enumerate(a, start=1):
        s = 0
        w = pow2[idx - 1]        # 2^{idx-1}
        for d in divisors[val]:
            s = (s + phi[d] * cum[d]) % MOD
            cum[d] = (cum[d] + w) % MOD
        dp = (dp * 2 + s) % MOD
        out.append(str(dp))

    sys.stdout.write("\n".join(out))


