# segment tree for range minimum (store A[i])
class SegTree:
    def __init__(self, data):
        n = len(data)
        size = 1
        while size < n:
            size <<= 1
        self.N = size
        self.inf = 10 ** 9
        self.t = [self.inf] * (2 * size)
        for i, v in enumerate(data):
            self.t[size + i] = v
        for i in range(size - 1, 0, -1):
            self.t[i] = min(self.t[i << 1], self.t[i << 1 | 1])

    # rightmost index in [l,r] with value < bound, -1 if none
    def rightmost_less(self, l, r, bound):
        return self._search(1, 0, self.N - 1, l, r, bound)

    def _search(self, node, nl, nr, ql, qr, bound):
        if nr < ql or nl > qr:
            return -1
        if self.t[node] >= bound:
            return -1
        if nl == nr:
            return nl
        mid = (nl + nr) >> 1
        # try right child first
        res = self._search(node << 1 | 1, mid + 1, nr, ql, qr, bound)
        if res != -1:
            return res
        return self._search(node << 1, nl, mid, ql, qr, bound)


