def solve() -> None:
    it = iter(sys.stdin.read().strip().split())
    N = int(next(it))
    A = [int(next(it)) for _ in range(N)]          # 0‑based, Ai < i  holds

    # --------------------------------------------------------
    # segment tree for minima of A
    seg = SegTree(A)

    left_child = [0] * (N + 1)   # 1‑based vertex numbers
    right_child = [0] * (N + 1)

    # stack for iterative construction: (L,R,parent)
    stack = [(0, N - 1, 0)]
    while stack:
        L, R, parent = stack.pop()
        if L > R:
            continue
        # bound = L+1  (because we need Ai < L+1  <->  Ai < (L+1))
        root_idx = seg.rightmost_less(L, R, L + 1)
        # root_idx is 0‑based, convert to 1‑based
        v = root_idx + 1

        # attach to its parent
        if parent != 0:
            if v < parent:
                left_child[parent] = v
            else:
                right_child[parent] = v

        # left part  [L , root_idx-1]
        if L <= root_idx - 1:
            stack.append((L, root_idx - 1, v))
        # right part [root_idx+1 , R]
        if root_idx + 1 <= R:
            stack.append((root_idx + 1, R, v))

    # --------------------------------------------------------
    # the whole tree has a unique root: the vertex that has no parent
    # (the global minimum). It is the vertex found for the whole range.
    root = seg.rightmost_less(0, N - 1, 1) + 1   # 1‑based

    # post‑order traversal to compute subtree sizes
    sz = [0] * (N + 1)
    prod = 1
    stack = [(root, False)]
    while stack:
        v, visited = stack.pop()
        if v == 0:
            continue
        if not visited:
            stack.append((v, True))
            if left_child[v]:
                stack.append((left_child[v], False))
            if right_child[v]:
                stack.append((right_child[v], False))
        else:
            s = 1
            if left_child[v]:
                s += sz[left_child[v]]
            if right_child[v]:
                s += sz[right_child[v]]
            sz[v] = s
            prod = prod * s % MOD

    # --------------------------------------------------------
    # factorials
    fac = [1] * (N + 1)
    for i in range(2, N + 1):
        fac[i] = fac[i - 1] * i % MOD

    ans = fac[N] * pow(prod, MOD - 2, MOD) % MOD
    print(ans)


