from typing import List

class Solution:
    def minOperations(self, nums: List[int]) -> int:
        if not nums:
            return 0

        # ---------- 1. smallest prime factor ----------
        limit = max(nums)
        spf = list(range(limit + 1))
        spf[0] = 0
        if limit >= 1:
            spf[1] = 1

        # classic O(limit log log limit) sieve
        for i in range(2, int(limit ** 0.5) + 1):
            if spf[i] == i:                     # i is prime
                step = i
                start = i * i
                for j in range(start, limit + 1, step):
                    if spf[j] == j:
                        spf[j] = i

        # ---------- 2. dynamic programming ----------
        dp = {}                 # value -> minimal operations so far

        for a in nums:
            # possible values at this position
            options = [(a, 0)]                     # keep original
            if a > 1:
                s = spf[a]
                if s != a:                         # composite -> we may replace
                    options.append((s, 1))

            new_dp = {}
            for val, cost in options:
                # cheapest previous value not larger than val
                best_prev = None
                for prev_val, prev_cost in dp.items():
                    if prev_val <= val:
                        if best_prev is None or prev_cost < best_prev:
                            best_prev = prev_cost
                if best_prev is not None:
                    total = best_prev + cost
                    if val not in new_dp or total < new_dp[val]:
                        new_dp[val] = total
            dp = new_dp
            if not dp:          # impossible to keep non‑decreasing
                return -1

        # answer = minimal cost among all possible final values
        return min(dp.values())

class Solution:
    def isBalanced(self, num: str) -> bool:
        """
        Returns True if the sum of digits at even indices equals the sum of
        digits at odd indices, otherwise returns False.
        """
        even_sum = 0
        odd_sum = 0

        for i, ch in enumerate(num):
            # Convert character to its numeric value
            digit = ord(ch) - ord('0')   # faster than int(ch)

            if i % 2 == 0:
                even_sum += digit
            else:
                odd_sum += digit

        return even_sum == odd_sum

