    def hasIncreasingSubarrays(self, nums: List[int], k: int) -> bool:
        n = len(nums)
        # The first subarray can start at any index a where a + 2*k <= n
        for a in range(n - 2 * k + 1):
            # Check whether nums[a : a+k] is strictly increasing
            inc1 = all(nums[a + i] < nums[a + i + 1] for i in range(k - 1))
            # The second subarray starts right after the first: b = a + k
            inc2 = all(nums[a + k + i] < nums[a + k + i + 1] for i in range(k - 1))
            if inc1 and inc2:
                return True
        return False

