class Solution:
    def minDifference(self, nums: List[int]) -> int:
        n = len(nums)
        if n == 0:
            return 0

        # 1. fixed known-known differences
        fixed = 0
        for i in range(n - 1):
            if nums[i] != -1 and nums[i + 1] != -1:
                diff = abs(nums[i] - nums[i + 1])
                if diff > fixed:
                    fixed = diff

        # 2. scan missing segments, compute D1
        D1 = 0
        i = 0
        while i < n:
            if nums[i] != -1:
                i += 1
                continue

            # start of a block of -1
            start = i
            while i < n and nums[i] == -1:
                i += 1
            end = i - 1                     # inclusive
            seg_len = end - start + 1

            left_idx = start - 1
            right_idx = end + 1

            left_val = nums[left_idx] if left_idx >= 0 else None
            right_val = nums[right_idx] if right_idx < n else None

            if left_val is not None and right_val is not None:
                gap = abs(left_val - right_val)
                if seg_len == 1:            # length 1 → stricter bound
                    # ceil(gap / 2)
                    need = (gap + 1) // 2
                    if need > D1:
                        D1 = need

        # 3. collect all known numbers that touch a -1
        S = []
        for idx, v in enumerate(nums):
            if v == -1:
                continue
            if (idx > 0 and nums[idx - 1] == -1) or (idx + 1 < n and nums[idx + 1] == -1):
                S.append(v)

        # 4. D2 from the covering condition
        if not S:
            D2 = 0
        else:
            mn = min(S)
            mx = max(S)
            D2 = (mx - mn + 2) // 3       # ceil( (mx-mn) / 3 )

        # 5. answer
        return max(fixed, D1, D2)

