class Solution:
    def minArraySum(self, nums: List[int], k: int, op1: int, op2: int) -> int:
        total = sum(nums)

        # Pre‑compute all possible choices for each element.
        # Each choice is a triple (use_op1, use_op2, gain) where gain is the reduction obtained.
        choices = []
        for x in nums:
            opts = [(0, 0, 0)]                     # do nothing
            opts.append((1, 0, x // 2))            # operation 1 only (divide by 2, round up)

            # operation 2 only (subtract k) – only possible when x >= k and k > 0
            if k > 0 and x >= k:
                opts.append((0, 1, k))             # operation 2 only

                # both operations on the same index
                # 1) subtract first, then divide
                y = x - k
                gain_sub_then_div = x - ((y + 1) // 2)   # ceil(y/2) = (y+1)//2

                # 2) divide first, then subtract (possible only if after division value >= k)
                if ((x + 1) // 2) >= k:
                    gain_div_then_sub = (x // 2) + k
                    gain_both = max(gain_sub_then_div, gain_div_then_sub)
                else:
                    gain_both = gain_sub_then_div

                opts.append((1, 1, gain_both))

            # if k == 0 the subtraction does nothing, we simply ignore it
            choices.append(opts)

        # DP[i][j] = maximum total reduction using i times op1 and j times op2
        NEG = -10**9
        dp = [[NEG] * (op2 + 1) for _ in range(op1 + 1)]
        dp[0][0] = 0

        for opts in choices:
            # copy current dp to avoid using an element more than once
            ndp = [row[:] for row in dp]
            for i in range(op1 + 1):
                for j in range(op2 + 1):
                    if dp[i][j] == NEG:
                        continue
                    cur = dp[i][j]
                    for d1, d2, gain in opts:
                        ni = i + d1
                        nj = j + d2
                        if ni <= op1 and nj <= op2:
                            if cur + gain > ndp[ni][nj]:
                                ndp[ni][nj] = cur + gain
            dp = ndp

        # We may not need to use all available operations
        best = 0
        for i in range(op1 + 1):
            for j in range(op2 + 1):
                if dp[i][j] > best:
                    best = dp[i][j]

        return total - best

class Solution:
    def possibleStringCount(self, word: str) -> int:
        """
        Returns the number of possible original strings that could have produced
        `word` when Alice may have held down a key too long at most once.
        """
        n = len(word)
        if n == 0:
            return 0

        # Count the number of runs (contiguous blocks of identical characters)
        runs = 1
        for i in range(1, n):
            if word[i] != word[i - 1]:
                runs += 1

        # Formula: n - runs + 1
        return n - runs + 1

