class Solution:
    def maxScore(self, n: int, k: int,
                 stayScore: List[List[int]],
                 travelScore: List[List[int]]) -> int:
        # dp_prev[c] = best score after the previous day being in city c
        dp_prev = [0] * n          # day -1 : starting point, no points yet

        for day in range(k):
            # staying in the same city
            stay = [dp_prev[c] + stayScore[day][c] for c in range(n)]

            # best travel from any previous city to each destination
            travel_max = [0] * n
            for p in range(n):
                base = dp_prev[p]
                row = travelScore[p]          # row[p][c] = travelScore[p][c]
                for c in range(n):
                    cand = base + row[c]
                    if cand > travel_max[c]:
                        travel_max[c] = cand

            # choose the better of staying or moving
            dp_cur = [max(stay[c], travel_max[c]) for c in range(n)]
            dp_prev = dp_cur

        return max(dp_prev)

class Solution:
    def smallestNumber(self, n: int, t: int) -> int:
        """
        Returns the smallest integer x >= n such that the product of the
        decimal digits of x is divisible by t.
        """
        # Helper: product of digits; returns 0 as soon as a zero digit is seen.
        def digit_product(x: int) -> int:
            prod = 1
            for ch in str(x):
                d = ord(ch) - 48          # faster than int(ch)
                if d == 0:                # product becomes 0
                    return 0
                prod *= d
            return prod

        # Every number is divisible by 1
        if t == 1:
            return n

        cur = n
        while True:
            if digit_product(cur) % t == 0:
                return cur
            cur += 1

class Solution:
    def smallestNumber(self, n: int) -> int:
        """
        Returns the smallest x >= n such that the binary representation of x
        contains only set bits (i.e., x = 2^k - 1 for some k).
        """
        # Number of bits required to represent n
        bits = n.bit_length()

        # All ones in 'bits' positions: 2^bits - 1
        candidate = (1 << bits) - 1

        # If this already satisfies the condition, return it;
        # otherwise use the next larger all‑ones number (bits+1).
        if candidate >= n:
            return candidate
        else:
            return (1 << (bits + 1)) - 1

