from itertools import combinations

class Solution:
    def maxRectangleArea(self, points: List[List[int]]) -> int:
        """
        Returns the maximal area of an axis‑parallel rectangle formed by four
        given points such that no other point lies inside or on its border.
        If no such rectangle exists, returns -1.
        """
        n = len(points)
        if n < 4:
            return -1

        # set for O(1) membership checks (not strictly needed here)
        point_set = set(tuple(p) for p in points)

        max_area = -1

        # iterate over all quadruples of distinct points
        for comb in combinations(points, 4):
            xs = {p[0] for p in comb}
            ys = {p[1] for p in comb}

            # need exactly two distinct x and two distinct y to form a rectangle
            if len(xs) != 2 or len(ys) != 2:
                continue

            xmin, xmax = sorted(xs)
            ymin, ymax = sorted(ys)

            # Check that the four corners are indeed present (they are, because
            # comb is a subset of points, but we keep the test for clarity)
            corners = {(xmin, ymin), (xmin, ymax), (xmax, ymin), (xmax, ymax)}
            if not corners.issubset(point_set):
                continue

            # Verify that no other point lies inside or on the border
            invalid = False
            for p in points:
                if p in corners:          # skip the rectangle's own corners
                    continue
                px, py = p
                if xmin <= px <= xmax and ymin <= py <= ymax:
                    invalid = True
                    break

            if not invalid:
                area = (xmax - xmin) * (ymax - ymin)
                if area > max_area:
                    max_area = area

        return max_area

import heapq

class Solution:
    def minOperations(self, n: int, m: int) -> int:
        # number of digits (both numbers have the same length)
        d = len(str(n))
        max_val = 10 ** d - 1

        # ---------- prime table ----------
        is_prime = [True] * (max_val + 1)
        if max_val >= 0:
            is_prime[0] = False
        if max_val >= 1:
            is_prime[1] = False
        limit = int(max_val ** 0.5) + 1
        for i in range(2, limit):
            if is_prime[i]:
                step = i
                start = i * i
                for j in range(start, max_val + 1, step):
                    is_prime[j] = False

        # ---------- trivial impossibility ----------
        if is_prime[n] or is_prime[m]:
            return -1
        if n == m:
            return n                       # no operation needed, cost = n

        # ---------- Dijkstra ----------
        INF = 10 ** 18
        dist = [INF] * (max_val + 1)
        dist[n] = n                         # start value is already counted
        heap = [(n, n)]

        # place[i] = 10^{d-1-i}
        place = [10 ** (d - 1 - i) for i in range(d)]

        while heap:
            cur_dist, u = heapq.heappop(heap)
            if cur_dist != dist[u]:
                continue
            if u == m:
                break                       # optimal distance reached

            # digits of u with leading zeroes
            s = str(u).zfill(d)
            for i, ch in enumerate(s):
                digit = ord(ch) - 48

                # increase this digit
                if digit < 9:
                    v = u + place[i]
                    if not is_prime[v]:
                        nd = cur_dist + v
                        if nd < dist[v]:
                            dist[v] = nd
                            heapq.heappush(heap, (nd, v))

                # decrease this digit
                if digit > 0:
                    v = u - place[i]
                    if not is_prime[v]:
                        nd = cur_dist + v
                        if nd < dist[v]:
                            dist[v] = nd
                            heapq.heappush(heap, (nd, v))

        return dist[m] if dist[m] != INF else -1

