class DSU:
    """ Disjoint Set Union with path compression and union by rank. """
    def __init__(self, n: int):
        self.parent = list(range(n))
        self.rank = [0] * n

    def find(self, x: int) -> int:
        # iterative version to avoid recursion depth issues
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x

    def union(self, x: int, y: int) -> None:
        xr = self.find(x)
        yr = self.find(y)
        if xr == yr:
            return
        if self.rank[xr] < self.rank[yr]:
            self.parent[xr] = yr
        elif self.rank[xr] > self.rank[yr]:
            self.parent[yr] = xr
        else:
            self.parent[yr] = xr
            self.rank[xr] += 1


class Solution:
    def countComponents(self, nums: List[int], threshold: int) -> int:
        n = len(nums)
        dsu = DSU(n)

        # map value -> original index, only needed for values <= threshold
        val_to_idx = {v: i for i, v in enumerate(nums)}

        # first divisor seen for each multiple m (1 .. threshold)
        first = [-1] * (threshold + 1)

        # unite numbers that share a common multiple <= threshold
        for a, idx in val_to_idx.items():
            if a > threshold:
                continue                # cannot connect with anyone
            step = a
            # all multiples of a up to threshold
            for m in range(a, threshold + 1, step):
                if first[m] == -1:
                    first[m] = idx
                else:
                    dsu.union(idx, first[m])

        # count distinct DSU roots
        roots = set()
        for i in range(n):
            roots.add(dsu.find(i))
        return len(roots)

