class Solution:
    def maxAmount(self, initialCurrency: str,
                  pairs1: List[List[str]], rates1: List[float],
                  pairs2: List[List[str]], rates2: List[float]) -> float:

        # -----------------------------------------------------------------
        # 1. collect all distinct currencies
        # -----------------------------------------------------------------
        currencies = set()
        currencies.add(initialCurrency)
        for a, b in pairs1:
            currencies.add(a)
            currencies.add(b)
        for a, b in pairs2:
            currencies.add(a)
            currencies.add(b)

        idx = {c: i for i, c in enumerate(sorted(currencies))}
        n = len(idx)

        # -----------------------------------------------------------------
        # 2. build the two max‑product matrices
        # -----------------------------------------------------------------
        def build_matrix(pairs, rates):
            mat = [[0.0] * n for _ in range(n)]
            for i in range(n):
                mat[i][i] = 1.0          # keep the currency unchanged

            for (u, v), r in zip(pairs, rates):
                u_i, v_i = idx[u], idx[v]
                # forward
                if r > mat[u_i][v_i]:
                    mat[u_i][v_i] = r
                # reverse (1/r)
                inv = 1.0 / r
                if inv > mat[v_i][u_i]:
                    mat[v_i][u_i] = inv
            return mat

        dp1 = build_matrix(pairs1, rates1)
        dp2 = build_matrix(pairs2, rates2)

        # -----------------------------------------------------------------
        # 3. Floyd‑Warshall for maximum product (day 1)
        # -----------------------------------------------------------------
        for k in range(n):
            dk = dp1[k]
            for i in range(n):
                if dp1[i][k] == 0.0:
                    continue
                di = dp1[i]
                aik = dp1[i][k]
                for j in range(n):
                    if dk[j] == 0.0:
                        continue
                    cand = aik * dk[j]
                    if cand > di[j]:
                        di[j] = cand

        # -----------------------------------------------------------------
        # 4. Floyd‑Warshall for maximum product (day 2)
        # -----------------------------------------------------------------
        for k in range(n):
            dk = dp2[k]
            for i in range(n):
                if dp2[i][k] == 0.0:
                    continue
                di = dp2[i]
                aik = dp2[i][k]
                for j in range(n):
                    if dk[j] == 0.0:
                        continue
                    cand = aik * dk[j]
                    if cand > di[j]:
                        di[j] = cand

        # -----------------------------------------------------------------
        # 5. combine the two days
        # -----------------------------------------------------------------
        s = idx[initialCurrency]
        answer = 1.0   # doing nothing is always possible
        for c in range(n):
            if dp1[s][c] == 0.0 or dp2[c][s] == 0.0:
                continue
            cand = dp1[s][c] * dp2[c][s]
            if cand > answer:
                answer = cand

        return answer

import sys

class Solution:
    def makeStringGood(self, s: str) -> int:
        n = len(s)
        cnt = [0] * 26
        for ch in s:
            cnt[ord(ch) - ord('a')] += 1

        # ---- build candidate frequencies ---------------------------------
        cand = {0}
        for i in range(26):
            if cnt[i]:
                cand.add(cnt[i])
            if i > 0 and cnt[i-1]:
                cand.add(cnt[i] + cnt[i-1])

        INF = 10 ** 9
        answer = n                     # delete everything

        # ---- DP for a fixed frequency ------------------------------------
        for f in cand:
            # dp[carry] = minimal cost, carry ∈ [0 .. f]
            dp = [INF] * (f + 1)
            dp[0] = 0

            for a in cnt:
                ndp = [INF] * (f + 1)
                for carry in range(f + 1):
                    cur = dp[carry]
                    if cur == INF:
                        continue
                    total = a + carry

                    # ----- letter is inactive (need = 0) -----
                    # delete everything
                    cost0 = cur + total
                    if cost0 < ndp[0]:
                        ndp[0] = cost0
                    # move everything forward (capped by f)
                    nc = total if total <= f else f
                    if cost0 < ndp[nc]:
                        ndp[nc] = cost0

                    # ----- letter is active (need = f) -----
                    if total >= f:
                        surplus = total - f          # will be moved forward
                        cost1 = cur + surplus
                        # forward the surplus
                        if cost1 < ndp[surplus]:
                            ndp[surplus] = cost1
                        # or delete the surplus (carry becomes 0)
                        if cost1 < ndp[0]:
                            ndp[0] = cost1
                    else:
                        deficit = f - total
                        cost1 = cur + deficit
                        if cost1 < ndp[0]:
                            ndp[0] = cost1
                dp = ndp

            # delete remaining carry
            for carry in range(f + 1):
                if dp[carry] != INF:
                    answer = min(answer, dp[carry] + carry)

        return answer

