class Solution:
    def countPathsWithXorValue(self, grid: List[List[int]], k: int) -> int:
        MOD = 10**9 + 7
        m, n = len(grid), len(grid[0])

        # dpPrev[j][x] = number of ways to reach cell (i‑1, j) with xor value x
        dpPrev = [[0] * 16 for _ in range(n)]

        for i in range(m):
            # dpCurr will hold the values for the current row i
            dpCurr = [[0] * 16 for _ in range(n)]
            for j in range(n):
                val = grid[i][j]
                if i == 0 and j == 0:          # start cell
                    dpCurr[j][val] = 1
                else:
                    # from the cell above (i‑1, j)
                    if i > 0:
                        for x in range(16):
                            cnt = dpPrev[j][x]
                            if cnt:
                                new_x = x ^ val
                                dpCurr[j][new_x] = (dpCurr[j][new_x] + cnt) % MOD
                    # from the cell on the left (i, j‑1)
                    if j > 0:
                        for x in range(16):
                            cnt = dpCurr[j-1][x]
                            if cnt:
                                new_x = x ^ val
                                dpCurr[j][new_x] = (dpCurr[j][new_x] + cnt) % MOD
            dpPrev = dpCurr  # move to the next row

        return dpPrev[n-1][k] % MOD
